// live_page_journeys.heuristics.mjs — Arc K Critic Layer 2 (heuristic judgment).
//
// Two exports:
//   CATALOG          — the full 209-rule skills-synthesis (designer/frontend/mobile-maestro/
//                      qa-tester/performance), generated by the K0 scout from the 5 UX skills.
//                      Reference/triage corpus (live_page_journeys_critic_catalog.json).
//   AUTO_HEURISTICS  — the subset that runs LIVE in-page each journey. Deliberately targets
//                      rules axe-core does NOT cover (taste, ARIA-state, motion, link safety) so
//                      they don't double-count the deterministic floor. Each detector fn runs in
//                      page context (self-contained — no external refs) and returns hit objects
//                      {sel, evidence}. The engine maps hits → severity-ranked findings[].
//
// DOCTRINE (BATTERY_ARCHITECTURE.md): the critic PROPOSES; humans triage Major+. Only the
// deterministic floor (axe/jscpd/measured) ratchets to 0. Heuristic findings are an advisory,
// severity-ranked backlog (0 Polish · 1 Minor · 2 Major · 3 Blocker).

import { readFileSync } from 'fs';

export const CATALOG = (() => {
  try { return JSON.parse(readFileSync('live_page_journeys_critic_catalog.json', 'utf8')); }
  catch (e) { return { count: 0, rules: [] }; }
})();

// ── live auto-detectors (axe-complementary) ─────────────────────────────────────
// Each: { id, rule, basis, severity, owner, fn }. fn(): in-page, returns [{sel, evidence}].
export const AUTO_HEURISTICS = [
  {
    id: 'H-dialog-aria', rule: 'Modal/bottom-sheet must carry role="dialog" + aria-modal="true" + an accessible name (aria-label OR a resolving aria-labelledby)',
    basis: 'designer / WCAG-4.1.2', severity: 2, owner: 'designer',
    fn: () => {
      const hits = [];
      const cands = [...document.querySelectorAll('.modal,.bottom-sheet,.sheet-overlay,.modal-overlay,[class*="modal"],[class*="overlay"],[class*="sheet"],[id*="modal"]')];
      for (const el of cands.slice(0, 30)) {
        // only flag overlays that look like a real dialog container (has a heading/buttons inside)
        if (!el.querySelector('h1,h2,h3,[class*="title"],button,input')) continue;
        const role = el.getAttribute('role'); const am = el.getAttribute('aria-modal');
        const lb = el.getAttribute('aria-labelledby'); const al = (el.getAttribute('aria-label') || '').trim();
        const lbOk = lb && document.getElementById(lb) && (document.getElementById(lb).textContent || '').trim();
        // an accessible name = a static aria-label (the documented fallback when a *-title is
        // JS-filled) OR a resolving, non-empty aria-labelledby. Either satisfies WCAG 4.1.2.
        const named = al.length > 0 || lbOk;
        if (role !== 'dialog' || am !== 'true' || !named) {
          const id = el.id || (el.className || '').toString().split(/\s+/).slice(0, 2).join('.');
          hits.push({ sel: (el.tagName.toLowerCase() + (el.id ? '#' + el.id : '.' + id)), evidence: `role=${role} aria-modal=${am} name=${named ? 'ok' : 'MISSING (no aria-label and no resolving aria-labelledby)'}` });
        }
      }
      return hits.slice(0, 6);
    },
  },
  {
    id: 'H-toggle-pressed', rule: 'Toggle/segmented buttons must expose aria-pressed (true|false) in parity with the .active class',
    basis: 'designer / WCAG-4.1.2', severity: 1, owner: 'designer',
    fn: () => {
      const vis = el => { const b = el.getBoundingClientRect(); const s = getComputedStyle(el); return b.width > 0 && b.height > 0 && s.visibility !== 'hidden' && s.display !== 'none'; };
      const hits = [];
      const toggles = [...document.querySelectorAll('.toggle-btn,.seg-btn,.view-tab,[role="tab"],.tab-btn,.filter-chip')].filter(vis);
      for (const el of toggles.slice(0, 40)) {
        const hasState = el.hasAttribute('aria-pressed') || el.hasAttribute('aria-selected') || el.getAttribute('role') === 'tab' && el.hasAttribute('aria-selected');
        if (!hasState) { const k = el.tagName.toLowerCase() + '.' + (el.className || '').toString().split(/\s+/).slice(0, 2).join('.'); hits.push({ sel: k, evidence: `"${(el.textContent || '').trim().slice(0, 20)}" has no aria-pressed/aria-selected` }); }
      }
      // collapse to unique class signatures
      const u = {}; for (const h of hits) u[h.sel] = (u[h.sel] || 0) + 1;
      return Object.entries(u).slice(0, 6).map(([sel, n]) => ({ sel, evidence: `${n} toggle(s) missing pressed/selected state` }));
    },
  },
  {
    id: 'H-live-region', rule: 'Auto-updating regions (toasts, connection/presence chips) must be ARIA live regions (role=status/alert + aria-live)',
    basis: 'designer / WCAG-4.1.3', severity: 1, owner: 'designer',
    fn: () => {
      const hits = [];
      const cands = [...document.querySelectorAll('[class*="toast"],[id*="toast"],[class*="snackbar"],[class*="conn-chip"],[class*="presence"],[class*="status-chip"]')];
      for (const el of cands.slice(0, 20)) {
        const role = el.getAttribute('role'); const live = el.getAttribute('aria-live');
        if (!(['status', 'alert'].includes(role) || ['polite', 'assertive'].includes(live))) {
          const k = el.tagName.toLowerCase() + (el.id ? '#' + el.id : '.' + (el.className || '').toString().split(/\s+/).slice(0, 2).join('.'));
          hits.push({ sel: k, evidence: `auto-update region without role=status/alert or aria-live` });
        }
      }
      return hits.slice(0, 5);
    },
  },
  {
    id: 'H-single-primary-cta', rule: 'An action card / hero CTA cluster should have ONE dominant primary CTA, not two equal-weight primaries',
    basis: 'designer / Nielsen-6 (recognition)', severity: 1, owner: 'designer',
    fn: () => {
      const vis = el => { const b = el.getBoundingClientRect(); const s = getComputedStyle(el); return b.width > 0 && b.height > 0 && s.visibility !== 'hidden' && s.display !== 'none'; };
      const hits = [];
      const clusters = [...document.querySelectorAll('.hero,.oh-card,#oh-today,#oh-actions,[class*="cta"],[class*="action-card"]')];
      for (const c of clusters.slice(0, 25)) {
        const prim = [...c.querySelectorAll('.btn-primary,button[class*="primary"],a[class*="primary"]')].filter(vis);
        if (prim.length > 1) { const k = c.tagName.toLowerCase() + (c.id ? '#' + c.id : '.' + (c.className || '').toString().split(/\s+/).slice(0, 2).join('.')); hits.push({ sel: k, evidence: `${prim.length} competing primary CTAs: ${prim.map(p => '"' + (p.textContent || '').trim().slice(0, 16) + '"').join(', ')}` }); }
      }
      return hits.slice(0, 5);
    },
  },
  {
    id: 'H-reduced-motion', rule: 'Decorative motion (e.g. .cta-pulse) must be disabled under prefers-reduced-motion',
    basis: 'designer / WCAG-2.3.3', severity: 1, owner: 'designer',
    fn: () => {
      const animated = [...document.querySelectorAll('.cta-pulse,[class*="pulse"],[class*="bounce"],[class*="spin"]')].filter(el => { const a = getComputedStyle(el).animationName; return a && a !== 'none'; });
      if (!animated.length) return [];
      // is there ANY @media (prefers-reduced-motion: reduce) rule in the stylesheets?
      let hasRule = false;
      for (const ss of document.styleSheets) { try { for (const r of ss.cssRules) { if (r.type === CSSRule.MEDIA_RULE && /prefers-reduced-motion/.test(r.conditionText || r.media.mediaText || '')) { hasRule = true; break; } } } catch (e) { } if (hasRule) break; }
      if (hasRule) return [];
      return [{ sel: '.cta-pulse', evidence: `${animated.length} animated element(s) and NO @media (prefers-reduced-motion: reduce) rule found` }];
    },
  },
  {
    id: 'H-blank-target-rel', rule: 'Links opening a new tab (target=_blank) must set rel="noopener" (reverse-tabnabbing + perf)',
    basis: 'security / performance', severity: 1, owner: 'security',
    fn: () => {
      const bad = [...document.querySelectorAll('a[target="_blank"]')].filter(a => !/noopener/.test(a.getAttribute('rel') || ''));
      return bad.slice(0, 6).map(a => ({ sel: 'a[href="' + (a.getAttribute('href') || '').slice(0, 40) + '"]', evidence: `target=_blank without rel=noopener` }));
    },
  },
  {
    id: 'H-heading-one', rule: 'A page should expose an <h1> landmark; the current state-view should surface a visible heading',
    basis: 'qa-tester / WCAG-1.3.1 (axe page-has-heading-one parity)', severity: 1, owner: 'qa-tester',
    fn: () => {
      const vis = el => { const b = el.getBoundingClientRect(); const s = getComputedStyle(el); return b.width > 0 && b.height > 0 && s.visibility !== 'hidden' && s.display !== 'none'; };
      const domH1 = document.querySelectorAll('h1').length;             // axe checks DOM presence
      const visH1 = [...document.querySelectorAll('h1')].filter(vis).length;
      if (domH1 === 0) return [{ sel: 'h1', severity: 2, evidence: `0 <h1> in DOM (page-has-heading-one fails)` }];
      // DOM has an h1 (axe passes). A state-view that hides ALL h1s (e.g. an authed dashboard
      // whose only h1 sits in a display:none landing) is a minor SR-nav nuance → S0 advisory.
      if (visH1 === 0) return [{ sel: 'h1', severity: 0, evidence: `h1 present in DOM (axe ok) but 0 visible in this state-view — consider a visible heading for SR nav` }];
      return [];
    },
  },
  {
    id: 'H-skip-link', rule: 'A keyboard skip-to-content link improves operability for keyboard/AT users',
    basis: 'qa-tester / WCAG-2.4.1', severity: 0, owner: 'qa-tester',
    fn: () => {
      const skip = [...document.querySelectorAll('a[href^="#"]')].some(a => /skip|main content|jump to/i.test((a.textContent || '') + ' ' + (a.className || '')));
      return skip ? [] : [{ sel: 'body', evidence: 'no skip-to-content link found' }];
    },
  },
];
